solution.css:
.blog-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
  max-width: 1000px;
  margin: 0 auto;
}

.post {
  background: #f0f0f0;
  padding: 20px;
  border-radius: 6px;
  min-height: 100px;
}

.featured {
  grid-column: 1 / -1;
  background: #ffd700;
}

.wide {
  grid-column: span 2;
  background: #87ceeb;
}

