solution.css:
.dashboard {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 16px;
  max-width: 1200px;
  margin: 0 auto;
}

.widget {
  background: #2d2d44;
  color: #eee;
  padding: 30px;
  border-radius: 8px;
  text-align: center;
  min-height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: bold;
}

.chart {
  background: #6c5ce7;
  grid-column: span 2;
}
